import jsonschema
from beeai.events import ResponseEvent

EXPECTED_SCHEMA = {
    'type': 'object',
    'properties': {
        'action': {'type': 'string'},
        'tool': {'type': 'string'},
        'parameters': {'type': 'object'}
    },
    'required': ['action']
}

class FormatValidator:
    def on_agent_response(self, event: ResponseEvent):
        try:
            parsed = json.loads(event.response)
            jsonschema.validate(instance=parsed, schema=EXPECTED_SCHEMA)
        except (json.JSONDecodeError, jsonschema.ValidationError) as e:
            print(f'🚨 GRANITE FORMAT ERROR: {str(e)[:100]}')
            print(f'Sample: {event.response[:200]}')
            event.set_retry()

validator = FormatValidator()
beeai.events.register('agent_response', validator.on_agent_response)

