import json
import uuid
from typing import Any
from beeai import AgentState

class AgentJSONEncoder(json.JSONEncoder):
    def default(self, obj: Any):
        if isinstance(obj, uuid.UUID):
            return str(obj)
        if hasattr(obj, '__dict__'):
            return obj.__dict__
        if isinstance(obj, set):
            return list(obj)
        return super().default(obj)

class SafeSerializer:
    def save_state(self, agent_state: AgentState, filepath: str):
        try:
            serializable = {
                'memory': agent_state.memory,
                'tools': [t.name for t in agent_state.tools],
                'session_id': str(agent_state.session_id),
                'timestamp': agent_state.last_updated
            }

            with open(filepath, 'w') as f:
                json.dump(serializable, f, cls=AgentJSONEncoder, indent=2)
            print(f'💾 State saved: {filepath}')

        except Exception as e:
            print(f'⚠️  Serialization fallback: {str(e)}')
            # Fallback to basic dict
            basic_state = {'memory': dict(list(agent_state.memory.items())[:100])}
            with open(filepath, 'w') as f:
                json.dump(basic_state, f)

serializer = SafeSerializer()
beeai.events.register('state_persist', lambda state: serializer.save_state(state, 'agent_state.json'))
